16	export function ConditionalEditor({ market }: ConditionalEditorProps) {
17	  const { session, isConfigured } = useSession();
18	  const mutation = useProbabilityEdit(market.id);
19	  const { data: marketsData } = useMarkets();
20	
21	  const [outcomeId, setOutcomeId] = useState(market.outcomes[0]?.id ?? "");
22	  const [probability, setProbability] = useState(0.5);
23	  const [context, setContext] = useState<ContextAssignment[]>([]);
24	
25	  const otherMarkets = (marketsData?.markets ?? []).filter(
26	    (m) => m.id !== market.id && m.status === "active",
27	  );
28	
29	  if (!isConfigured) {
30	    return (
31	      <div style={panelStyle}>
32	        <div style={{ color: "var(--color-text-muted)", textAlign: "center" }}>
33	          Set your Account ID in the header to use conditional edits.
34	        </div>
35	      </div>
36	    );
37	  }
38	
39	  const addContext = () => {
40	    if (otherMarkets.length === 0) return;
41	    setContext([...context, { variableId: "", outcomeId: "" }]);
42	  };
43	
44	  const removeContext = (idx: number) => {
45	    setContext(context.filter((_, i) => i !== idx));
46	  };
47	
48	  const updateContext = (idx: number, field: keyof ContextAssignment, value: string) => {
49	    const next = [...context];
50	    next[idx] = { ...next[idx]!, [field]: value };
51	    if (field === "variableId") {
52	      next[idx]!.outcomeId = "";
53	    }
54	    setContext(next);
55	  };
56	
57	  const handleSubmit = (e: React.FormEvent) => {
58	    e.preventDefault();
59	    const validContext = context.filter((c) => c.variableId && c.outcomeId);
60	    mutation.mutate({
61	      payload: {
62	        accountId: session.accountId,
63	        variableId: market.variableId,
64	        target: { kind: "marginal", outcomeId, probability },
65	        context: validContext,
66	        idempotencyKey: crypto.randomUUID(),
67	      },
68	      session,
69	    });
70	  };
71	
72	  const hasContext = context.length > 0;
73	
74	  return (
75	    <div style={panelStyle}>
76	      <h3 style={{ fontSize: "1rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>
77	        Conditional Probability Edit
78	      </h3>
79	      <p style={{ fontSize: "0.8rem", color: "var(--color-text-muted)", marginBottom: "var(--space-md)" }}>
80	        {hasContext
81	          ? `Set P(${market.outcomes.find((o) => o.id === outcomeId)?.name ?? outcomeId} | ${context
82	              .filter((c) => c.variableId && c.outcomeId)
83	              .map((c) => `${c.variableId}=${c.outcomeId}`)
84	              .join(", ")}) = ${formatProbability(probability)}`
85	          : `Set P(${market.outcomes.find((o) => o.id === outcomeId)?.name ?? outcomeId}) = ${formatProbability(probability)}`}
86	      </p>
87	
88	      <form onSubmit={handleSubmit} style={{ display: "grid", gap: "var(--space-md)" }}>
89	        {/* Target outcome and probability */}
90	        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "var(--space-md)" }}>
91	          <label style={{ fontSize: "0.85rem" }}>
92	            <span style={labelStyle}>Target Outcome</span>
93	            <select value={outcomeId} onChange={(e) => setOutcomeId(e.target.value)} style={inputStyle}>
94	              {market.outcomes.map((o) => (
95	                <option key={o.id} value={o.id}>
96	                  {o.name} (current: {formatProbability(market.marginals[o.id] ?? 0)})
97	                </option>
98	              ))}
99	            </select>
100	          </label>
101	          <label style={{ fontSize: "0.85rem" }}>
102	            <span style={labelStyle}>New Probability: {formatProbability(probability)}</span>
103	            <input
104	              type="range"
105	              min={0.01}
106	              max={0.99}
107	              step={0.01}
108	              value={probability}
109	              onChange={(e) => setProbability(Number(e.target.value))}
110	              style={{ width: "100%" }}
111	            />
112	          </label>
113	        </div>
114	
115	        {/* Context conditions */}
116	        <div>
117	          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
118	            <span style={{ fontSize: "0.85rem", fontWeight: 500 }}>
119	              Conditions (given that...)
120	            </span>
121	            <button
122	              type="button"
123	              onClick={addContext}
124	              disabled={otherMarkets.length === 0}
125	              style={addBtnStyle}
126	            >
127	              + Add condition
128	            </button>
129	          </div>
130	
131	          {context.length === 0 && (
132	            <div style={{ fontSize: "0.8rem", color: "var(--color-text-muted)", padding: "var(--space-sm)", background: "var(--color-bg)", borderRadius: "var(--radius-sm)" }}>
133	              No conditions — this is an unconditional edit. Add conditions to make it conditional.
134	            </div>
135	          )}
136	
137	          {context.map((c, idx) => (
138	            <ContextRow
139	              key={idx}
140	              assignment={c}
141	              otherMarkets={otherMarkets}
142	              onUpdate={(field, value) => updateContext(idx, field, value)}
143	              onRemove={() => removeContext(idx)}
144	            />
145	          ))}
146	        </div>
147	
148	        <button
149	          type="submit"
150	          disabled={mutation.isPending}
151	          style={{
152	            padding: "8px 16px",
153	            borderRadius: "var(--radius-sm)",
154	            border: "none",
155	            background: hasContext ? "var(--color-info)" : "var(--color-primary)",
156	            color: "#fff",
157	            fontWeight: 600,
158	            cursor: mutation.isPending ? "not-allowed" : "pointer",
159	            opacity: mutation.isPending ? 0.6 : 1,
160	          }}
161	        >
162	          {mutation.isPending
163	            ? "Submitting…"
164	            : hasContext
165	              ? "Submit Conditional Edit"
166	              : "Submit Unconditional Edit"}
167	        </button>
168	      </form>
169	
170	      {mutation.isSuccess && (
171	        <div style={successStyle}>
172	          {hasContext ? "Conditional edit" : "Edit"} accepted: {mutation.data.order.orderId}
173	        </div>
174	      )}
175	
176	      {mutation.isError && (
177	        <div style={errorStyle}>
178	          {mutation.error instanceof Error ? mutation.error.message : "Edit failed"}
179	        </div>
180	      )}
181	    </div>
182	  );
183	}
184	
185	function ContextRow({
186	  assignment,
187	  otherMarkets,
188	  onUpdate,
189	  onRemove,
190	}: {
191	  assignment: ContextAssignment;
192	  otherMarkets: MarketSummary[];
193	  onUpdate: (field: keyof ContextAssignment, value: string) => void;
194	  onRemove: () => void;
195	}) {
196	  const { data } = useMarket(assignment.variableId, { enabled: !!assignment.variableId });
197	  const outcomes = data?.market.outcomes ?? [];
198	
199	  return (
200	    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr auto", gap: "var(--space-sm)", marginBottom: "var(--space-sm)" }}>
201	      <select
202	        value={assignment.variableId}
203	        onChange={(e) => onUpdate("variableId", e.target.value)}
204	        style={inputStyle}
205	      >
206	        <option value="">Select market...</option>
207	        {otherMarkets.map((m) => (
208	          <option key={m.id} value={m.id}>{m.title}</option>
209	        ))}
210	      </select>
211	      <select
212	        value={assignment.outcomeId}
213	        onChange={(e) => onUpdate("outcomeId", e.target.value)}
214	        style={inputStyle}
215	        disabled={!assignment.variableId}
216	      >
217	        <option value="">Select outcome...</option>
218	        {outcomes.map((o) => (
219	          <option key={o.id} value={o.id}>{o.name}</option>
220	        ))}
221	      </select>
222	      <button type="button" onClick={onRemove} style={removeBtnStyle}>×</button>
223	    </div>
224	  );
225	}
