27	        <div
28	          style={{
29	            height: "100%",
30	            width: `${barPct}%`,
31	            borderRadius: 3,
32	            background: barPct > 80 ? "var(--color-danger)" : barPct > 50 ? "var(--color-warning, orange)" : "var(--color-success)",
33	            transition: "width 0.3s ease",
34	          }}
35	        />
36	      </div>
37	    </div>
38	  );
